/* ── Main Popup Component ── */
function NewsletterPopup({ onClose }) {
  const [email, setEmail]     = useState('');
  const [loading, setLoading] = useState(false);
  const [message, setMessage] = useState({ text: '', type: '' });
  const [bannerData, setBannerData] = useState(null);
  const [visible, setVisible] = useState(false);

  // Fetch popup banner data from Django
  useEffect(() => {
    axios
      .get(`${API_BASE}/popup/`)
      .then((res) => setBannerData(res.data))
      .catch(() => setBannerData(null));

    // Trigger entrance animation
    const t = setTimeout(() => setVisible(true), 50);
    return () => clearTimeout(t);
  }, []);

  // Close on Escape key
  useEffect(() => {
    const handleKeyDown = (e) => {
      if (e.key === 'Escape') {
        setVisible(false);
        setTimeout(onClose, 300);
      }
    };
    document.addEventListener('keydown', handleKeyDown);
    return () => document.removeEventListener('keydown', handleKeyDown);
  }, [onClose]);

  const handleClose = () => {
    setVisible(false);
    setTimeout(onClose, 300);
  };

  const handleOverlayClick = (e) => {
    if (e.target === e.currentTarget) handleClose();
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!email.trim()) {
      setMessage({ text: 'Please enter your email address.', type: 'error' });
      return;
    }
    setLoading(true);
    setMessage({ text: '', type: '' });
    try {
      await axios.post(`${API_BASE}/subscribe/`, { email: email.trim() });
      setMessage({ text: 'Successfully subscribed! Thank you.', type: 'success' });
      setEmail('');
      setTimeout(handleClose, 2000);
    } catch (err) {
      const errorMsg =
        err.response?.data?.errors?.email?.[0] ||
        err.response?.data?.message ||
        'Something went wrong. Please try again.';
      setMessage({ text: errorMsg, type: 'error' });
    } finally {
      setLoading(false);
    }
  };

  const title = bannerData?.title || 'Subscribe Newsletter';

  return (
    <div
      className={`popup-overlay ${visible ? 'visible' : ''}`}
      onClick={handleOverlayClick}
      role="dialog"
      aria-modal="true"
      aria-labelledby="popup-title"
    >
      <div className={`popup-modal ${visible ? 'visible' : ''}`}>

        {/* Close Button */}
        <button
          className="popup-close"
          onClick={handleClose}
          aria-label="Close newsletter popup"
        >
          ✕
        </button>

        {/* Left — Image / Illustration */}
        <div className="popup-image-section">
          {bannerData?.image_url ? (
            <img
              src={bannerData.image_url}
              alt="Newsletter promotion"
              className="popup-image"
            />
          ) : (
            <PopupIllustration />
          )}
        </div>

        {/* Right — Content */}
        <div className="popup-content-section">
          <h2 id="popup-title" className="popup-title">
            {title}
          </h2>
          <p className="popup-subtitle">
            Subscribe the <strong>TheMart</strong> to get latest products and
            discount update.
          </p>

          <form onSubmit={handleSubmit} className="popup-form" noValidate>
            <input
              type="email"
              className="popup-input"
              placeholder="Enter your email address......"
              value={email}
              onChange={(e) => setEmail(e.target.value)}
              disabled={loading}
              aria-label="Email address"
              autoComplete="email"
            />

            {message.text && (
              <p className={`popup-message ${message.type}`} role="alert">
                {message.text}
              </p>
            )}

            <button
              type="submit"
              className="popup-subscribe-btn"
              disabled={loading}
            >
              {loading ? 'SUBSCRIBING...' : 'SUBSCRIBE'}
            </button>
          </form>
        </div>

      </div>
    </div>
  );
}

export default NewsletterPopup;
